@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_8b41b4a9dfc7499da07746f22dd797f9.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation
@implements IDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p class="text-muted"><small>Refreshing…</small></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _loadCts;
    private readonly CancellationTokenSource _disposeCts = new();

    protected override Task OnInitializedAsync()
    {
        _loadedCuisineId = CuisineId;
        return LoadRecipesAsync();
    }

    protected override Task OnParametersSetAsync()
    {
        // Only reload if the cuisine changed; sort changes don't trigger a reload.
        if (CuisineId != _loadedCuisineId)
        {
            _loadedCuisineId = CuisineId;
            return LoadRecipesAsync();
        }

        return Task.CompletedTask;
    }

    private IEnumerable<Recipe> DisplayedRecipes =>
        Sort?.Equals("popular", StringComparison.OrdinalIgnoreCase) == true
            ? _recipes!.OrderByDescending(r => r.PrepTimeMinutes)
            : _recipes!.OrderByDescending(r => r.Id);

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }

        _loadCts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);
        var cts = _loadCts;

        _error = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);

            if (cts.Token.IsCancellationRequested)
                return;

            _recipes = result;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // Expected when switching cuisines or disposing — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
            _isRefreshing = false;
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
            _isRefreshing = false;
        }
    }

    private Task RetryAsync() => LoadRecipesAsync();

    public void Dispose()
    {
        _disposeCts.Cancel();
        _disposeCts.Dispose();
        _loadCts?.Dispose();
    }
}

